Use ASP.NET Core's `WebApplicationFactory<TEntryPoint>` — it hosts your app in-memory and gives you an `HttpClient` that talks to it without opening a real port.

**1. Add the test package:**

```bash
dotnet add package Microsoft.AspNetCore.Mvc.Testing
```

**2. Write a test class:**

```csharp
using Microsoft.AspNetCore.Mvc.Testing;
using System.Net.Http.Json;
using System.Text.Json;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.Equal(1, body.GetProperty("id").GetInt32());
        Assert.True(body.GetProperty("result").TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        // Initialize first
        await InitializeSession();

        var request = new { jsonrpc = "2.0", id = 2, method = "tools/list" };
        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }

    private async Task InitializeSession()
    {
        var init = new
        {
            jsonrpc = "2.0", id = 0, method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" }
            }
        };
        await _client.PostAsJsonAsync("/mcp", init);
    }
}
```

**3. Override services if needed** (e.g., swap a real DB for an in-memory one):

```csharp
_client = factory.WithWebHostBuilder(builder =>
{
    builder.ConfigureServices(services =>
    {
        // Replace real dependencies with test doubles
        services.AddSingleton<IMyService, FakeMyService>();
    });
}).CreateClient();
```

**Key points:**

- **No real port** — `WebApplicationFactory` uses an in-memory `TestServer` under the hood.
- **Full pipeline** — middleware, routing, DI, serialization all run exactly as in production.
- **`Program` must be visible** — add `public partial class Program { }` at the bottom of your entry point, or use `[InternalsVisibleTo]`.
- **Stateful sessions** — if your MCP server tracks session state, either use one `HttpClient` per logical session or configure the `Mcp-Session-Id` header as needed by the Streamable HTTP transport spec.
